    31→        getNextPageParam: (lastPage) =>{
    32→            if(lastPage?.hasMore){
    33→                const lastOpinion = lastPage?.data[lastPage?.data?.length - 1];
    34→                return lastOpinion.id;
    35→            } else {
    36→                return undefined
