     1→import { useQuery, useQueryClient } from "@tanstack/react-query";
     2→import { useLocation } from "react-router-dom";
     3→import { addReplyOpinion, getViewOpinion } from "../../../API/Api";
     4→import { useAuth } from "../../Context/useAuth";
     5→import { useState, useRef } from "react";
     6→import { motion, AnimatePresence } from "framer-motion";
     7→import formatPostDate from "../../../helpers/formatDateString";
     8→import OpinionsReplyCard from "./OpinionsCardRepy";
     9→
    10→const OpinionViewer = () => {
    11→    const queryClient = useQueryClient();
    12→    const location = useLocation();
    13→    const { opinionId, userId } = location.state;
    14→    const { user } = useAuth();
    15→    const textAreaRef = useRef(null);
    16→
    17→    const [replyOpinion, setReplyOpinion] = useState('');
    18→    const [isTyping, setIsTyping] = useState(false);
    19→
    20→    const { data, isLoading } = useQuery({
    21→        queryKey: ['getViewOpinion', opinionId, userId],
    22→        queryFn: ({ queryKey }) => getViewOpinion(queryKey[1], queryKey[2]),
    23→        staleTime: 1000 * 60 * 60,
    24→        cacheTime: 1000 * 60 * 60,
    25→        enabled: !!opinionId && !!userId,
    26→        refetchOnWindowFocus: false
    27→    });
    28→
    29→    const cancelTyping = () => {
    30→        setIsTyping(false);
    31→        setReplyOpinion('');
    32→        if (textAreaRef.current) {
    33→            textAreaRef.current.innerText = '';
    34→            textAreaRef.current.blur();
    35→        }
    36→    };
    37→
    38→    const submitReply = async (receiverId, senderId, parentId) => {
    39→        const formData = new FormData();
    40→        formData.append('opinion', replyOpinion);
    41→
    42→        try {
    43→            await addReplyOpinion(formData, receiverId, senderId, parentId);
    44→            setReplyOpinion('');
    45→            if (textAreaRef.current) {
    46→                textAreaRef.current.innerText = '';
    47→            }
    48→            queryClient.invalidateQueries(['getViewOpinion', opinionId, receiverId]);
    49→        } catch (error) {
    50→            console.error(error);
    51→            setReplyOpinion('');
    52→            if (textAreaRef.current) {
    53→                textAreaRef.current.innerText = '';
    54→            }
    55→            queryClient.invalidateQueries(['getViewOpinion', opinionId, receiverId]);
    56→        }
    57→    };
    58→
    59→    const opinionData = data?.data;
    60→
    61→    return (
    62→        <>
    63→            {opinionData?.map((opinion) => (
    64→                <motion.div
    65→                    className="ov-card"
    66→                    key={opinion.id}
    67→                    initial={{ opacity: 0, y: 12 }}
    68→                    animate={{ opacity: 1, y: 0 }}
    69→                    transition={{ duration: 0.3, ease: "easeOut" }}
    70→                >
    71→                    <div className="ov-user-row">
    72→                        <img
    73→                            className="ov-avatar"
    74→                            src={opinion.users.image_url || '../assets/profile.jpg'}
    75→                            alt=""
    76→                        />
    77→                        <span className="ov-username">{opinion.users.name}</span>
    78→                        <span className="ov-dot">·</span>
    79→                        <span className="ov-date">{formatPostDate(opinion.created_at)}</span>
    80→                    </div>
    81→
    82→                    <div className="ov-body">
    83→                        {opinion.opinion}
    84→                    </div>
    85→
    86→                    <div className="ov-meta-bar">
    87→                        <span className="ov-reply-pill">
    88→                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    89→                                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
    90→                            </svg>
    91→                            {opinion.reply_count} {opinion.reply_count === 1 ? 'reply' : 'replies'}
    92→                        </span>
    93→                        <span className="ov-full-date">
    94→                            {new Date(opinion.created_at).toLocaleDateString('en-US', {
    95→                                month: 'long',
    96→                                day: '2-digit',
    97→                                year: 'numeric',
    98→                            })}
    99→                        </span>
   100→                    </div>
   101→
   102→                    <div className="ov-reply-row">
   103→                        <img
   104→                            className="ov-reply-avatar"
   105→                            src={user?.userData[0].image_url || '../assets/profile.jpg'}
   106→                            alt=""
   107→                        />
   108→                        <div
   109→                            className="ov-reply-input"
   110→                            onFocus={() => setIsTyping(true)}
   111→                            ref={textAreaRef}
   112→                            onInput={(e) => setReplyOpinion(e.currentTarget.innerText.trim())}
   113→                            data-placeholder={`Add a reply to '${opinion.users.name}'`}
   114→                            contentEditable="true"
   115→                            role="textbox"
   116→                        />
   117→                    </div>
   118→
   119→                    <AnimatePresence>
   120→                        {isTyping && (
   121→                            <motion.div
   122→                                className="ov-btn-row"
   123→                                initial={{ height: 0, opacity: 0 }}
   124→                                animate={{ height: "auto", opacity: 1 }}
   125→                                exit={{ height: 0, opacity: 0 }}
   126→                                transition={{ duration: 0.2 }}
   127→                            >
   128→                                <button
   129→                                    onClick={cancelTyping}
   130→                                    className="ov-btn-cancel"
   131→                                >
   132→                                    Cancel
   133→                                </button>
   134→                                <button
   135→                                    disabled={replyOpinion.trim().length === 0}
   136→                                    onClick={() => submitReply(userId, user?.userData[0].id, opinion.id)}
   137→                                    className={`ov-btn-submit ${replyOpinion.trim().length === 0 ? 'ov-btn-disabled' : ''}`}
   138→                                >
   139→                                    Submit
   140→                                </button>
   141→                            </motion.div>
   142→                        )}
   143→                    </AnimatePresence>
   144→
   145→                    <OpinionsReplyCard opinionId={opinion.id} depth={0} />
   146→                </motion.div>
   147→            ))}
   148→        </>
   149→    );
   150→};
   151→
   152→export default OpinionViewer;
   153→

